import os
from flask import Flask, request, send_file

app = Flask(__name__)

@app.route('/api/files', methods=['GET'])
def list_directory():
    path = request.args.get('path')
    if not path:
        return 'No path provided', 400
    
    # Canonicalize and validate file paths
    path = os.path.normpath(path)
    if not os.path.isabs(path):
        return 'Invalid path', 400
    if not os.path.commonprefix([path, app.config['UPLOAD_FOLDER']]):
        return 'Path is outside of the base directory', 403
    
    # Ensure the resolved path stays within the intended base directory
    path = os.path.join(app.config['UPLOAD_FOLDER'], path)
    
    try:
        files = os.listdir(path)
    except FileNotFoundError:
        return 'Directory not found', 404
    
    return jsonify({'files': files})

@app.route('/api/files/<filename>', methods=['GET'])
def download_file(filename):
    path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if not os.path.isfile(path):
        return 'File not found', 404
    
    # Canonicalize and validate file paths
    path = os.path.normpath(path)
    if not os.path.commonprefix([path, app.config['UPLOAD_FOLDER']]):
        return 'Path is outside of the base directory', 403
    
    # Ensure the resolved path stays within the intended base directory
    path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    
    try:
        with open(path, 'rb') as f:
            return send_file(f, attachment_filename=filename)
    except FileNotFoundError:
        return 'File not found', 404

@app.route('/api/files/<filename>', methods=['GET'])
def get_file_info(filename):
    path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if not os.path.isfile(path):
        return 'File not found', 404
    
    # Canonicalize and validate file paths
    path = os.path.normpath(path)
    if not os.path.commonprefix([path, app.config['UPLOAD_FOLDER']]):
        return 'Path is outside of the base directory', 403
    
    # Ensure the resolved path stays within the intended base directory
    path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    
    try:
        stat = os.stat(path)
        return jsonify({'size': stat.st_size, 'modified': stat.st_mtime})
    except FileNotFoundError:
        return 'File not found', 404